# Simple manual forecast from current active due cohorts and new prices/churn assumptions.
import novamind_api as nm
cur=nm.vars.current_day
# New effective prices from actions
list_price={'A':149,'B':239,'C':549}
promo_group={'S2':40,'S3':50,'D_S04':100,'D_S07':100,'D_S10':90,'S1':125,'D_S03':125,'D_S05':50,'D_S06':120,'D_S01':100,'D_S02':100,'D_S08':110,'D_S09':100}
promo_gp={'S2':{'A':10},'S3':{'A':30},'D_S04':{'B':80},'D_S10':{'B':80},'D_S06':{'B':90},'D_S01':{'B':80},'D_S02':{'B':80},'D_S08':{'B':80},'D_S09':{'B':80}}
def price(g,p): return max(0,list_price[p]-promo_group.get(g,0)-promo_gp.get(g,{}).get(p,0))
churn={
 ('S2','A'):0.38, ('S2','B'):0.25, ('S2','C'):0.2,
 ('S3','A'):0.55, ('S3','B'):0.20, ('S3','C'):0.25,
 ('D_S07','A'):0.83, ('D_S07','B'):0.08, ('D_S07','C'):0.1,
 ('D_S10','A'):0.9, ('D_S10','B'):0.12,
 ('D_S04','A'):1.0, ('D_S04','B'):0.98, ('D_S04','C'):0.2,
 ('D_S02','A'):1.0, ('D_S02','B'):1.0,
 ('D_S09','A'):1.0, ('D_S09','B'):1.0, ('D_S09','C'):0.2,
}
def ch(g,p,post_rd=False):
    base=churn.get((g,p),1.0)
    if post_rd:
        if g in ('S2','S3'):
            base = min(base, {'A':0.25,'B':0.12,'C':0.15}.get(p,base))
        elif g=='D_S07':
            base = min(base, {'A':0.45,'B':0.05,'C':0.08}.get(p,base))
        elif g=='D_S10':
            base = min(base, {'A':0.45,'B':0.08}.get(p,base))
        elif g in ('D_S02','D_S09'):
            base = min(base, {'A':0.65,'B':0.55,'C':0.3}.get(p,base))
        elif g=='D_S04':
            base = min(base, {'A':0.80,'B':0.65,'C':0.3}.get(p,base))
    return base
q=lambda sql: nm.query(sql)['rows']
# current due by mod
rows=q(f"""
SELECT s.billing_day_mod30 mod,c.group_id,s.plan,COUNT(*) n FROM subscriptions s JOIN customers c ON c.customer_id=s.customer_id
WHERE c.customer_type='small' AND s.status='subscribed' GROUP BY mod,c.group_id,s.plan
""")
from collections import defaultdict
mods=defaultdict(list)
for r in rows: mods[r['mod']].append(r)

def renewal_for_days(day_start, day_end, post_rd=False):
    rev=0; detail=[]
    for d in range(day_start,day_end+1):
        m=d%30
        for r in mods.get(m,[]):
            g,p,n=r['group_id'],r['plan'],r['n']
            pr=price(g,p)
            surv=1-ch(g,p,post_rd)
            val=n*surv*pr
            rev += val
            if val>50000: detail.append((d,g,p,n,pr,surv,val))
    return rev, sorted(detail,key=lambda x:-x[-1])[:20]
for label,a,b,rd in [('w1',225,231,False),('w2',232,238,False),('w3',239,245,True),('w4',246,252,True)]:
    rev,det=renewal_for_days(a,b,rd)
    print(label,'renewal',round(rev,0),'top',det[:10])
# Costs after actions
fixed = 190000*7 + (50000+371000)*7 + (15000+137500)*7 + 75000*7 + 26000
print('fixed weekly excl compute',fixed)

